1	type Item = { type: string; enchantment?: number; cursed?: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Step = {
4	  op: string;
5	  items?: Item[];
6	  policy?: number;
7	  incident?: { cause?: string; damages: Damage[] };
8	};
9	type Scenario = {
10	  customer?: { yearsWithMHPCO?: number };
11	  steps: Step[];
12	};
13	
14	const PROCESSING_FEE = 5;
15	const DEDUCTIBLE_PER_DAMAGE = 100;
16	const CAP_MULTIPLIER = 2;
17	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	const BLOCK_OF_3_PRICE = 60;
34	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
37	const CURSE_SURCHARGE_RATE = 0.5;
38	const LOYALTY_THRESHOLD_YEARS = 2;
39	const LOYALTY_DISCOUNT_RATE = 0.2;
40	const FIRST_INSURANCE_RATE = 0.1;
41	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
42	
43	function quotePremium(
44	  items: Item[],
45	  yearsWithMHPCO: number,
46	  quoteIndex: number,
47	): number {
48	  const countsByType: Record<string, number> = {};
49	  for (const item of items) {
50	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
51	  }
52	  let policyBase = 0;
53	  for (const [type, count] of Object.entries(countsByType)) {
54	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
55	      policyBase += BLOCK_OF_3_PRICE;
56	    } else {
57	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
58	    }
59	  }
60	  let itemSurcharges = 0;
61	  for (const item of items) {
62	    let surchargeRate = 0;
63	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
64	      surchargeRate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
65	    }
66	    if (item.cursed) {
67	      surchargeRate += CURSE_SURCHARGE_RATE;
68	    }
69	    itemSurcharges += surchargeRate * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
70	  }
71	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
72	  const loyaltyDiscount =
73	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
74	  const followUpDiscount = quoteIndex >= 1 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
75	  return (
76	    Math.ceil(
77	      policyBase + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount,
78	    ) + PROCESSING_FEE
79	  );
80	}
81	
82	function processClaim(
83	  claimStep: Step,
84	  steps: Step[],
85	  remainingCapByPolicy: Record<number, number>,
86	): { payout: number; remainingCap: number } {
87	  const policyIndex = claimStep.policy!;
88	  const policyItems = steps[policyIndex].items ?? [];
89	  if (!(policyIndex in remainingCapByPolicy)) {
90	    const insuranceSum = policyItems.reduce(
91	      (sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type],
92	      0,
93	    );
94	    remainingCapByPolicy[policyIndex] = CAP_MULTIPLIER * insuranceSum;
95	  }
96	  const damages = claimStep.incident?.damages ?? [];
97	  const grossPayout = damages.reduce(
98	    (sum, d) => sum + Math.max(0, d.amount - DEDUCTIBLE_PER_DAMAGE),
99	    0,
100	  );
101	  const payout = Math.min(
102	    Math.floor(grossPayout),
103	    remainingCapByPolicy[policyIndex],
104	  );
105	  remainingCapByPolicy[policyIndex] -= payout;
106	  return { payout, remainingCap: remainingCapByPolicy[policyIndex] };
107	}
108	
109	export function processScenario(scenario: unknown): unknown {
110	  const { customer, steps } = scenario as Scenario;
111	  const yearsWithMHPCO = customer?.yearsWithMHPCO ?? 0;
112	  const remainingCapByPolicy: Record<number, number> = {};
113	  let quoteIndex = 0;
114	  const results = steps.map((step) => {
115	    if (step.op === "claim") {
116	      return processClaim(step, steps, remainingCapByPolicy);
117	    }
118	    const premium = quotePremium(step.items ?? [], yearsWithMHPCO, quoteIndex);
119	    quoteIndex += 1;
120	    return { premium };
121	  });
122	  return { results };
123	}
